import axios, { AxiosInstance, AxiosError, AxiosRequestConfig } from 'axios';
import { API_CONFIG } from './config';
import { addCSRFHeader } from '../security/csrf';
import { ApiError } from '../types';

/**
 * Create an Axios instance with secure defaults
 */
const createApiClient = (): AxiosInstance => {
  const client = axios.create({
    baseURL: API_CONFIG.baseURL,
    timeout: API_CONFIG.timeout,
    headers: API_CONFIG.headers,
    withCredentials: true, // Include cookies in requests
  });

  // Request interceptor for authentication and CSRF
  client.interceptors.request.use(
    (config) => {
      // Add CSRF token to headers
      config.headers = addCSRFHeader(config.headers);
      
      // Add auth token if available
      const token = localStorage.getItem('auth_token');
      if (token) {
        config.headers.Authorization = `Bearer ${token}`;
      }
      
      return config;
    },
    (error) => Promise.reject(error)
  );

  // Response interceptor for error handling
  client.interceptors.response.use(
    (response) => response,
    async (error: AxiosError<ApiError>) => {
      if (error.response) {
        // Handle specific status codes
        switch (error.response.status) {
          case 401:
            // Token expired - try to refresh
            try {
              await refreshToken();
              // Retry original request
              return client.request(error.config as AxiosRequestConfig);
            } catch {
              // Refresh failed - redirect to login
              window.location.href = '/login';
            }
            break;
          
          case 403:
            // Forbidden - CSRF token might be invalid
            console.error('CSRF validation failed');
            break;
          
          case 429:
            // Rate limit exceeded
            const retryAfter = error.response.headers['retry-after'];
            console.error(`Rate limit exceeded. Retry after ${retryAfter} seconds`);
            break;
        }
      }
      
      return Promise.reject(error);
    }
  );

  return client;
};

/**
 * Refresh authentication token
 */
async function refreshToken(): Promise<void> {
  const refreshToken = localStorage.getItem('refresh_token');
  if (!refreshToken) {
    throw new Error('No refresh token available');
  }

  const response = await axios.post(
    `${API_CONFIG.baseURL}${API_CONFIG.endpoints.auth.refresh}`,
    { refresh_token: refreshToken }
  );

  const { access_token, refresh_token: newRefreshToken } = response.data;
  localStorage.setItem('auth_token', access_token);
  localStorage.setItem('refresh_token', newRefreshToken);
}

/**
 * API client instance
 */
export const apiClient = createApiClient();

/**
 * Type-safe API request wrapper
 */
export async function apiRequest<T>(
  config: AxiosRequestConfig
): Promise<T> {
  try {
    const response = await apiClient.request<T>(config);
    return response.data;
  } catch (error) {
    if (axios.isAxiosError(error) && error.response?.data) {
      throw error.response.data;
    }
    throw error;
  }
} 