'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  MessageSquare, Search, Settings, LogOut, Plus,
  Calendar, Clock, X, Scale, BookOpen, Shield, HelpCircle,
  ChevronDown, ChevronRight, History
} from 'lucide-react';
import { ChatSession } from '@/lib/types';
import { chatService } from '@/services/chat.service';
import { cn } from '@/lib/utils/cn';

interface SidebarProps {
  currentSessionId?: string;
  onSessionSelect: (sessionId: string) => void;
  onNewChat: () => void;
}

const navigationItems = [
  { icon: MessageSquare, label: 'Chat', id: 'chat', active: true },
  { icon: Scale, label: 'Legal Resources', id: 'resources' },
  { icon: Shield, label: 'Security', id: 'security' },
  { icon: HelpCircle, label: 'Help', id: 'help' },
  { icon: History, label: 'History', id: 'history' },
];

export function Sidebar({ currentSessionId, onSessionSelect, onNewChat }: SidebarProps) {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [activeSection, setActiveSection] = useState('chat');
  const [isHistoryExpanded, setIsHistoryExpanded] = useState(true);

  useEffect(() => {
    loadSessions();
  }, []);

  const loadSessions = async () => {
    try {
      setIsLoading(true);
      const data = await chatService.getSessions();
      setSessions(data);
    } catch (error) {
      console.error('Failed to load sessions:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDeleteSession = async (sessionId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    
    try {
      await chatService.deleteSession(sessionId);
      setSessions((prev) => prev.filter((s) => s.id !== sessionId));
      
      if (currentSessionId === sessionId) {
        onNewChat();
      }
    } catch (error) {
      console.error('Failed to delete session:', error);
    }
  };

  const filteredSessions = sessions.filter((session) =>
    session.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const formatDate = (date: Date) => {
    const now = new Date();
    const sessionDate = new Date(date);
    const diffInDays = Math.floor((now.getTime() - sessionDate.getTime()) / (1000 * 60 * 60 * 24));

    if (diffInDays === 0) return 'Today';
    if (diffInDays === 1) return 'Yesterday';
    if (diffInDays < 7) return `${diffInDays} days ago`;
    return sessionDate.toLocaleDateString();
  };

  const groupedSessions = filteredSessions.reduce((groups, session) => {
    const date = formatDate(session.createdAt);
    if (!groups[date]) {
      groups[date] = [];
    }
    groups[date].push(session);
    return groups;
  }, {} as Record<string, ChatSession[]>);

  return (
    <aside className="w-64 h-full bg-gray-950 border-r border-gray-800 flex flex-col">
      {/* Top Search */}
      <div className="p-4 border-b border-gray-800">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-gray-500" />
          <input
            type="text"
            placeholder="Search Ctrl+K"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full rounded-lg bg-gray-900 border border-gray-700 py-2 pl-10 pr-4 text-sm text-gray-300 placeholder-gray-500 focus:border-gray-600 focus:outline-none transition-colors"
          />
        </div>
      </div>

      {/* Navigation */}
      <div className="flex-1 overflow-y-auto">
        <div className="p-2">
          {navigationItems.map((item) => (
            <button
              key={item.id}
              onClick={() => {
                setActiveSection(item.id);
                if (item.id === 'chat') {
                  onNewChat();
                }
              }}
              className={cn(
                "flex items-center gap-3 w-full px-3 py-2 text-sm rounded-lg transition-colors",
                activeSection === item.id
                  ? "bg-gray-800 text-white"
                  : "text-gray-400 hover:text-gray-300 hover:bg-gray-900"
              )}
            >
              <item.icon className="h-5 w-5" />
              {item.label}
              {item.id === 'history' && (
                <motion.div
                  animate={{ rotate: isHistoryExpanded ? 90 : 0 }}
                  transition={{ duration: 0.2 }}
                  onClick={(e) => {
                    e.stopPropagation();
                    setIsHistoryExpanded(!isHistoryExpanded);
                  }}
                  className="ml-auto"
                >
                  <ChevronRight className="h-4 w-4" />
                </motion.div>
              )}
            </button>
          ))}
        </div>

        {/* Chat History Section */}
        <AnimatePresence>
          {activeSection === 'history' && isHistoryExpanded && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: "auto" }}
              exit={{ opacity: 0, height: 0 }}
              className="px-2 pb-4"
            >
              {isLoading ? (
                <div className="flex items-center justify-center py-8">
                  <div className="h-6 w-6 animate-spin rounded-full border-2 border-gray-600 border-t-transparent" />
                </div>
              ) : Object.keys(groupedSessions).length === 0 ? (
                <div className="text-center py-6">
                  <p className="text-gray-500 text-sm">No conversations yet</p>
                </div>
              ) : (
                <div className="space-y-4">
                  {Object.entries(groupedSessions).map(([date, sessions]) => (
                    <div key={date} className="space-y-1">
                      <h3 className="text-xs font-medium text-gray-500 uppercase tracking-wider px-3 py-1">
                        {date}
                      </h3>
                      {sessions.map((session) => (
                        <motion.div
                          key={session.id}
                          className={cn(
                            'group relative w-full rounded-lg p-2 transition-colors cursor-pointer',
                            currentSessionId === session.id
                              ? 'bg-gray-800 text-white'
                              : 'hover:bg-gray-900 text-gray-400'
                          )}
                          whileHover={{ x: 2 }}
                        >
                          <div 
                            className="flex items-start gap-2"
                            onClick={() => onSessionSelect(session.id)}
                          >
                            <MessageSquare className="h-4 w-4 mt-0.5 flex-shrink-0" />
                            <div className="flex-1 min-w-0">
                              <p className="font-medium text-sm truncate">
                                {session.title}
                              </p>
                              <div className="mt-1 flex items-center gap-1 text-xs text-gray-500">
                                <Clock className="h-3 w-3" />
                                <span>{new Date(session.updatedAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                              </div>
                            </div>
                            <button
                              onClick={(e) => handleDeleteSession(session.id, e)}
                              className="opacity-0 group-hover:opacity-100 transition-opacity p-1 rounded hover:bg-gray-700"
                            >
                              <X className="h-3 w-3 text-gray-500 hover:text-gray-300" />
                            </button>
                          </div>
                        </motion.div>
                      ))}
                    </div>
                  ))}
                </div>
              )}
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      {/* Bottom Actions */}
      <div className="border-t border-gray-800 p-2">
        <button className="flex items-center gap-3 w-full px-3 py-2 text-sm text-gray-400 hover:text-gray-300 hover:bg-gray-900 rounded-lg transition-colors">
          <Settings className="h-4 w-4" />
          Settings
        </button>
        <button className="flex items-center gap-3 w-full px-3 py-2 text-sm text-gray-400 hover:text-red-400 hover:bg-gray-900 rounded-lg transition-colors">
          <LogOut className="h-4 w-4" />
          Sign Out
        </button>
      </div>
    </aside>
  );
} 