'use client';

import React from 'react';
import { motion } from 'framer-motion';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { BookOpen, FileText, Gavel, ScrollText, User, Bot, Scale, Sparkles } from 'lucide-react';
import { Message as MessageType, LegalSource } from '@/lib/types';
import { cn } from '@/lib/utils/cn';
import { Card } from '@/components/ui/Card';

interface MessageProps {
  message: MessageType;
  isTyping?: boolean;
}

const sourceIcons: Record<LegalSource['type'], React.ReactNode> = {
  case_law: <Gavel className="h-4 w-4" />,
  statute: <BookOpen className="h-4 w-4" />,
  regulation: <FileText className="h-4 w-4" />,
  policy: <ScrollText className="h-4 w-4" />,
};

export function Message({ message, isTyping = false }: MessageProps) {
  const isUser = message.role === 'user';

  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3 }}
      className={cn(
        'flex gap-4 px-6 py-6',
        isUser ? 'flex-row-reverse' : 'flex-row'
      )}
    >
      {/* Avatar */}
      <motion.div
        className={cn(
          'flex h-12 w-12 shrink-0 items-center justify-center rounded-2xl shadow-lg',
          isUser
            ? 'bg-gradient-to-br from-amber-500 to-red-500'
            : 'bg-gradient-to-br from-slate-700 to-zinc-700'
        )}
        whileHover={{ scale: 1.1, rotate: 5 }}
        transition={{ type: "spring", stiffness: 300 }}
      >
        {isUser ? (
          <User className="h-6 w-6 text-white" />
        ) : (
          <Scale className="h-6 w-6 text-white" />
        )}
      </motion.div>

      {/* Message Content */}
      <div className={cn('flex max-w-[70%] flex-col gap-3', isUser && 'items-end')}>
        <motion.div
          initial={{ scale: 0.95 }}
          animate={{ scale: 1 }}
          transition={{ duration: 0.2 }}
        >
          <Card
            variant={isUser ? 'default' : 'glass'}
            className={cn(
              'relative overflow-hidden transition-all duration-300',
              isUser 
                ? 'bg-gradient-to-br from-amber-950/30 to-red-950/30 border-amber-800' 
                : 'backdrop-blur-xl bg-black/50 border-white/10 shadow-xl'
            )}
          >
            {/* Shimmer effect for assistant messages */}
            {!isUser && (
              <motion.div
                className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent"
                animate={{ x: ['-100%', '100%'] }}
                transition={{ duration: 3, repeat: Infinity, ease: "linear", repeatDelay: 2 }}
              />
            )}

            {isTyping ? (
              <div className="flex items-center gap-2 px-6 py-4">
                <motion.div
                  className="flex items-center gap-1"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ duration: 0.3 }}
                >
                  <span className="h-2 w-2 animate-bounce rounded-full bg-amber-500 [animation-delay:-0.3s]" />
                  <span className="h-2 w-2 animate-bounce rounded-full bg-amber-500 [animation-delay:-0.15s]" />
                  <span className="h-2 w-2 animate-bounce rounded-full bg-amber-500" />
                </motion.div>
              </div>
            ) : (
              <div className="relative px-6 py-4">
                <div className="prose prose-sm dark:prose-invert max-w-none">
                  <ReactMarkdown 
                    remarkPlugins={[remarkGfm]}
                    components={{
                      code: ({ className, children, ...props }) => {
                        const match = /language-(\w+)/.exec(className || '');
                        return match ? (
                          <pre className="rounded-lg bg-white/5 p-3 overflow-x-auto">
                            <code className={className} {...props}>
                              {children}
                            </code>
                          </pre>
                        ) : (
                          <code className="rounded bg-amber-900/30 px-1.5 py-0.5 text-amber-200" {...props}>
                            {children}
                          </code>
                        );
                      },
                    }}
                  >
                    {message.content}
                  </ReactMarkdown>
                </div>
              </div>
            )}
          </Card>
        </motion.div>

        {/* Legal Sources */}
        {message.metadata?.sources && message.metadata.sources.length > 0 && (
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
            className="flex flex-wrap gap-2"
          >
            <span className="flex items-center gap-1 text-xs text-amber-400 font-medium">
              <Sparkles className="h-3 w-3" />
              Sources:
            </span>
            {message.metadata.sources.map((source, index) => (
              <motion.a
                key={index}
                href={source.url}
                target="_blank"
                rel="noopener noreferrer"
                className="group flex items-center gap-1.5 rounded-lg bg-gradient-to-r from-amber-900/30 to-red-900/30 px-3 py-1.5 text-xs font-medium text-amber-200 transition-all hover:shadow-md"
                whileHover={{ scale: 1.05, y: -2 }}
                whileTap={{ scale: 0.95 }}
              >
                {sourceIcons[source.type]}
                <span className="max-w-[200px] truncate">{source.title}</span>
                <motion.div
                  className="h-1 w-1 rounded-full bg-amber-500"
                  animate={{
                    scale: [1, 1.5, 1],
                    opacity: [0.5, 1, 0.5],
                  }}
                  transition={{
                    duration: 2,
                    repeat: Infinity,
                    ease: "easeInOut",
                  }}
                />
              </motion.a>
            ))}
          </motion.div>
        )}

        {/* Timestamp and metadata */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.3 }}
          className="flex items-center gap-3 text-xs text-gray-400"
        >
          <span>{new Date(message.timestamp).toLocaleTimeString()}</span>
          {message.metadata?.processingTime && (
            <>
              <span>•</span>
              <span>{(message.metadata.processingTime / 1000).toFixed(2)}s</span>
            </>
          )}
          {message.metadata?.confidence && (
            <>
              <span>•</span>
              <span className="flex items-center gap-1">
                <motion.div
                  className="h-2 w-16 rounded-full bg-gray-700 overflow-hidden"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                >
                  <motion.div
                    className="h-full bg-gradient-to-r from-amber-500 to-red-500"
                    initial={{ width: 0 }}
                    animate={{ width: `${message.metadata.confidence * 100}%` }}
                    transition={{ duration: 0.5, delay: 0.2 }}
                  />
                </motion.div>
                <span>{Math.round(message.metadata.confidence * 100)}%</span>
              </span>
            </>
          )}
        </motion.div>
      </div>
    </motion.div>
  );
}